First Attempt at creating something like a cline SDK, where users can invoke cline and interact with cline interactively: here's an example script interacting with cline interactively:

The approach i took to making a cline sdk was basically have it conform exactly to the ACP protocol but instead of using stdin/stdout, we use javascript event emitters. People are familar with ACP by now and they are definitely familiar with event emitters. This unlocks a whole new set of use cases for using Cline programmatically. First use case I can think of it creating some programmatic end to end tests.

```ts
import { ClineAgent } from "cline";
import { NewSessionResponse, PROTOCOL_VERSION } from "@agentclientprotocol/sdk";

const clineAgent = new ClineAgent({
    version: "0.0.1",
    clineDir: "/Users/maxpaulus/.cline",
});

const { agentInfo, authMethods } = await clineAgent.initialize({
    clientCapabilities: { fs: { readTextFile: true, writeTextFile: true } },
    protocolVersion: PROTOCOL_VERSION,
});

console.log("Agent name:", agentInfo?.name);
console.log(
    "Auth Methods:",
    authMethods?.map((m) => m.id),
);

let session: NewSessionResponse | undefined;
try {
    session = await clineAgent.newSession({
        cwd: process.cwd(),
        mcpServers: [],
    });
} catch (err: unknown) {
    if ((err as any).code === -32000) {
        // auth error
        await clineAgent.authenticate({ methodId: "openai-codex-oauth" });
        console.log("Authenticated!");
        session = await clineAgent.newSession({
            cwd: process.cwd(),
            mcpServers: [],
        });
    }
}

clineAgent.setSessionMode({ sessionId: session!.sessionId, modeId: "plan" });

const sessionEvents = clineAgent.emitterForSession(session!.sessionId);
sessionEvents.on("agent_message_chunk", (payload) => {
    if (payload.content.type === "text") {
        process.stdout.write(payload.content.text);
    }
});

const response = await clineAgent.prompt({
    sessionId: session!.sessionId,
    prompt: [
        {
            type: "text",
            text: "What is the capital of florida? Tell me a joke about florida",
        },
    ],
});

console.log("\n\nPrompt response:", response);

```



Here's another even more interactive example (taking multiple conversation turns)

```ts
import { ClineAgent, ClineAcpSession } from "cline";
import { NewSessionResponse, PROTOCOL_VERSION } from "@agentclientprotocol/sdk";
import * as readline from "node:readline";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
});

// ---------------------------------------------------------------------------
// Bootstrap the agent
// ---------------------------------------------------------------------------

const clineAgent = new ClineAgent({
    clineDir: "/Users/maxpaulus/.cline",
});

const { agentInfo, authMethods } = await clineAgent.initialize({
    clientCapabilities: { fs: { readTextFile: true, writeTextFile: true } },
    protocolVersion: PROTOCOL_VERSION,
});

console.log("Agent name:", agentInfo?.name);
console.log(
    "Auth Methods:",
    authMethods?.map((m) => m.id),
);

// Handle auth if needed (try creating a throwaway session)
let session: NewSessionResponse | null = null;
async function createSession() {
    session = await clineAgent.newSession({
        cwd: process.cwd(),
        mcpServers: [],
    });
    // Use act mode so the agent actually performs actions
    await clineAgent.setSessionMode({
        sessionId: session!.sessionId,
        modeId: "act",
    });
    // Stream agent output
    const emitter = clineAgent.emitterForSession(session!.sessionId);
    emitter.on("agent_message_chunk", (payload) => {
        if (payload.content.type === "text") {
            process.stdout.write(payload.content.text);
        }
    });
}

try {
    await createSession();
} catch (err: unknown) {
    if ((err as any).code !== -32000) throw err;
    await clineAgent.authenticate({ methodId: "openai-codex-oauth" });
    console.log("Authenticated!");
    await createSession();
}

// ---------------------------------------------------------------------------
// Permission handler – interactive stdin prompt
// ---------------------------------------------------------------------------
//
clineAgent.sessions.values().next().value?.mode;

clineAgent.setPermissionHandler(async (request) => {
    // Build a human-readable description from the tool call
    const toolName =
        request.toolCall?.title ?? request.toolCall?.kind ?? "unknown action";

    // Build shortcut map from the available options
    const shortcuts: { key: string; label: string; optionId: string }[] = [];
    for (const opt of request.options) {
        switch (opt.kind) {
            case "allow_once":
                shortcuts.push({
                    key: "a",
                    label: "allow",
                    optionId: opt.optionId,
                });
                break;
            case "allow_always":
                shortcuts.push({
                    key: "A",
                    label: "always allow",
                    optionId: opt.optionId,
                });
                break;
            case "reject_once":
                shortcuts.push({
                    key: "r",
                    label: "reject",
                    optionId: opt.optionId,
                });
                break;
            case "reject_always":
                shortcuts.push({
                    key: "R",
                    label: "always reject",
                    optionId: opt.optionId,
                });
                break;
        }
    }

    const choicesStr = shortcuts.map((s) => `${s.label} (${s.key})`).join(", ");
    const prompt = `\nCline asks permission to do '${toolName}': ${choicesStr}: `;

    // Use the readline interface to get user input
    rl.question(prompt, (answer) => {
        const trimmed = answer.trim();
        const match = shortcuts.find((s) => s.key === trimmed);
        if (match) {
            return {
                outcome: { outcome: "selected", optionId: match.optionId },
            };
        } else {
            // Default to first option if unrecognised input
            console.log(
                `  (unrecognised input "${trimmed}", defaulting to "${shortcuts[0]?.label}")`,
            );
            return {
                outcome: {
                    outcome: "selected",
                    optionId: shortcuts[0]?.optionId ?? "",
                },
            };
        }
    });

    return {
        outcome: {
            outcome: "selected",
            optionId: request.options[0]?.optionId ?? "",
        },
    };
});

const tasksWithinSameSession = [
    "Create a file called hello.txt with the text 'Hello World'",
    "same with 'Goodbye World'",
];

for (let i = 0; i < tasksWithinSameSession.length; i++) {
    const taskText = tasksWithinSameSession[i];

    console.log(`\n${"=".repeat(60)}`);
    console.log(`  Cline: ${taskText}`);
    console.log(`${"=".repeat(60)}\n`);

    // Send the prompt and wait for completion
    const response = await clineAgent.prompt({
        sessionId: session!.sessionId,
        prompt: [{ type: "text", text: taskText }],
    });

    console.log(`\n\n[Cline Prompt response:`, response.stopReason);
    console.log(
        `\n\nMoving on to next task with same session`,
        response.stopReason,
    );
}

console.log("\nAll 3 tasks complete!");
rl.close();
await clineAgent.shutdown();

```


